const formData = $('parse-input').first().json;
const merged = $('merge-outputs').first().json;
const ops = $input.first().json?.message?.content || $input.first().json?.choices?.[0]?.message?.content || '';

return [{
  json: {
    businessName: formData.businessName,
    goal: formData.goal,
    budget: formData.budget,
    industry: formData.industry,
    email: formData.email,
    timestamp: formData.timestamp,
    researchSummary: merged.researchReport.substring(0, 500),
    contentSummary: merged.contentPackage.substring(0, 500),
    analyticsSummary: merged.analyticsReport.substring(0, 500),
    operationsPlan: ops.substring(0, 500),
    status: 'COMPLETED'
  }
}];
